#!/usr/bin/env python3
"""Generate machine-readable retention-risk summary.

Usage: generate_retention_report.py <workspace-root>
Outputs a single-line JSON object to stdout.
"""

from __future__ import annotations

import json
import re
import sys
from pathlib import Path


def read_text(path: Path) -> str:
    return path.read_text(encoding="utf-8")


def total_full_time_nurses(roster_text: str) -> int:
    m = re.search(r"Full-Time Staff\s*\((\d+)\s*FTE\)", roster_text, re.I)
    if m:
        return int(m.group(1))
    # Fallback: count RN rows in the full-time staff table.
    return len(re.findall(r"^\|\s*RN-\d+\s*\|", roster_text, re.M))


def audit_manual_hours_by_name(audit_text: str) -> dict[str, float]:
    hours: dict[str, float] = {}
    for line in audit_text.splitlines():
        if not line.startswith("| RN-"):
            continue
        cells = [c.strip().strip("*") for c in line.strip().strip("|").split("|")]
        if len(cells) < 4:
            continue
        name = re.sub(r"\s*\([^)]*\)", "", cells[1]).strip()
        try:
            hours[name] = float(cells[3])
        except ValueError:
            continue
    return hours


def main() -> None:
    if len(sys.argv) != 2:
        raise SystemExit("Usage: generate_retention_report.py <workspace-root>")

    root = Path(sys.argv[1])
    retention = json.loads(read_text(root / "analysis" / "retention_risk_assessment.json"))
    roster = read_text(root / "nurse_roster_current.md")
    audit = read_text(root / "overtime_audit_report.md")

    at_risk_count = int(retention["at_risk_count"])
    total_nurses = total_full_time_nurses(roster)
    audit_hours = audit_manual_hours_by_name(audit)

    at_risk_names = [n["name"] for n in retention.get("at_risk_nurses", [])]
    at_risk_hours = [audit_hours[name] for name in at_risk_names if name in audit_hours]

    result = {
        "at_risk_count": at_risk_count,
        "total_nurses": total_nurses,
        "risk_rate_pct": round((at_risk_count / total_nurses) * 100, 1) if total_nurses else 0.0,
        "highest_hours_at_risk": max(at_risk_hours) if at_risk_hours else 0.0,
    }
    print(json.dumps(result, separators=(",", ":")))


if __name__ == "__main__":
    main()

